from flask import Flask, redirect, url_forfrom flask_mysqldb import MySQLapp = Flask(__name__)# =========================# CONFIGURATION DATABASE# =========================app.config['MYSQL_HOST'] = 'localhost'app.config['MYSQL_USER'] = 'root'app.config['MYSQL_PASSWORD'] = ''app.config['MYSQL_DB'] = 'dbtest'mysql = MySQL(app)# =========================# IMPORT DES MODULES (CRUD)# =========================from bus import bus_bp, init_busfrom chauffeur import chauffeur_bp, init_chauffeurfrom ligne import ligne_bp, init_lignefrom reservation import reservation_bp, init_reservation# =========================# INITIALISATION (IMPORTANT)# =========================init_bus(mysql)init_chauffeur(mysql)init_ligne(mysql)init_reservation(mysql)# =========================# ENREGISTREMENT DES ROUTES# =========================app.register_blueprint(bus_bp)app.register_blueprint(chauffeur_bp)app.register_blueprint(ligne_bp)app.register_blueprint(reservation_bp)# =========================# PAGE D'ACCUEIL# =========================@app.route('/')def home():    return redirect(url_for('bus.bus'))# =========================# LANCEMENT APP# =========================if __name__ == "__main__":    app.run(debug=True)